// Parse research agent output, merge with trigger input so full pipeline state flows through
const raw = $input.first().json;
const triggerIn = $('When Executed by Parent').first().json;
let research;
try {
  const text = typeof raw.output === 'string' ? raw.output : JSON.stringify(raw.output);
  const m = text.match(/\{[\s\S]*\}/);
  research = JSON.parse(m ? m[0] : text);
  if (!research.researchNotes) throw new Error('Missing researchNotes');
} catch(e) {
  research = {
    topic: triggerIn.topic || '',
    keyFacts: [],
    angles: [],
    sourcesMentioned: [],
    researchNotes: '',
    researchParseError: e.message
  };
}

return {
  json: {
    ...triggerIn,
    research: research
  }
};
